import React from 'react'
import * as RadixNavigationMenu from '@radix-ui/react-navigation-menu'

export interface NavigationMenuProps extends React.ComponentPropsWithoutRef<typeof RadixNavigationMenu.Root> {}

export const NavigationMenu = React.forwardRef<
  React.ElementRef<typeof RadixNavigationMenu.Root>,
  NavigationMenuProps
>(({ className, children, ...props }, ref) => (
  <RadixNavigationMenu.Root ref={ref} className={className} {...props}>
    {children}
    <NavigationMenuViewport />
  </RadixNavigationMenu.Root>
))
NavigationMenu.displayName = 'NavigationMenu'

